CREATE TABLE IF NOT EXISTS meetings (meeting_id VARCHAR(50) PRIMARY KEY, title VARCHAR(200) NOT NULL, date DATE NOT NULL, time_start TIME NOT NULL, time_end TIME NOT NULL, location VARCHAR(200) DEFAULT '社區活动中心', host VARCHAR(100) NOT NULL, agenda JSONB, action_items JSONB, created_at TIMESTAMP DEFAULT NOW(), updated_at TIMESTAMP DEFAULT NOW())
CREATE TABLE IF NOT EXISTS meeting_speakers (id SERIAL PRIMARY KEY, meeting_id VARCHAR(50) REFERENCES meetings(meeting_id), speaker_name VARCHAR(100) NOT NULL, speaker_unit VARCHAR(10), speaker_role VARCHAR(50), voice_profile_id UUID, created_at TIMESTAMP DEFAULT NOW())
CREATE INDEX IF NOT EXISTS idx_meeting_speakers_speaker_role ON meeting_speakers (speaker_role)
CREATE TABLE IF NOT EXISTS meeting_segments (id SERIAL PRIMARY KEY, meeting_id VARCHAR(50) REFERENCES meetings(meeting_id), speaker_id INTEGER REFERENCES meeting_speakers(id), start REAL NOT NULL, end REAL NOT NULL, text TEXT NOT NULL, confidence REAL DEFAULT 0.0)
CREATE TABLE IF NOT EXISTS meeting_action_items (id SERIAL PRIMARY KEY, meeting_id VARCHAR(50) REFERENCES meetings(meeting_id), item TEXT NOT NULL, owner VARCHAR(100), deadline DATE, status VARCHAR(20) DEFAULT 'pending', created_at TIMESTAMP DEFAULT NOW())
CREATE INDEX IF NOT EXISTS idx_meeting_action_items_owner ON meeting_action_items (owner)
CREATE TABLE IF NOT EXISTS meeting_files (id SERIAL PRIMARY KEY, meeting_id VARCHAR(50) REFERENCES meetings(meeting_id), file_name VARCHAR(255) NOT NULL, file_path TEXT NOT NULL, file_type VARCHAR(50) DEFAULT 'audio', file_size BIGINT, created_at TIMESTAMP DEFAULT NOW())
CREATE TABLE IF NOT EXISTS meeting_notes (id SERIAL PRIMARY KEY, meeting_id VARCHAR(50) REFERENCES meetings(meeting_id), note TEXT NOT NULL, note_type VARCHAR(50) DEFAULT 'general', created_by VARCHAR(100), created_at TIMESTAMP DEFAULT NOW())
CREATE INDEX IF NOT EXISTS idx_meeting_notes_created_by ON meeting_notes (created_by)